import { DrugInfo, DiagnosisInfo, Language } from "../types";

const API_KEY = process.env.API_KEY;

// Use proxy paths configured in vite.config.ts / vercel.json to avoid CORS
const TEXT_API_URL = "/api/qwen/text"; 
const VL_API_URL = "/api/qwen/multimodal";

// Helper to call Qwen API
const callQwen = async (messages: any[], model: string = 'qwen-plus') => {
  if (!API_KEY) throw new Error("API Key is missing");

  try {
    const response = await fetch(TEXT_API_URL, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${API_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        model: model,
        input: { messages: messages },
        parameters: { result_format: 'message' } // simplified return
      })
    });

    if (!response.ok) {
      const err = await response.json();
      throw new Error(err.message || "Qwen API Error");
    }

    const data = await response.json();
    return data.output.choices[0].message.content;
  } catch (error) {
    console.error("Qwen Service Error:", error);
    throw error;
  }
};

// Helper to call Qwen VL API
const callQwenVL = async (messages: any[]) => {
    if (!API_KEY) throw new Error("API Key is missing");

    try {
      const response = await fetch(VL_API_URL, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${API_KEY}`,
          'Content-Type': 'application/json',
          'X-DashScope-WorkSpace': 'modal'
        },
        body: JSON.stringify({
          model: 'qwen-vl-max',
          input: { messages: messages },
          parameters: {}
        })
      });

      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.message || "Qwen VL API Error");
      }

      const data = await response.json();
      return data.output.choices[0].message.content[0].text;
    } catch (error) {
      console.error("Qwen VL Service Error:", error);
      throw error;
    }
  };

// --- Prompts ---

const getSystemPrompt = (lang: Language, type: 'DRUG' | 'DIAGNOSIS') => {
    if (type === 'DRUG') {
      return `You are a senior clinical pharmacist. 
      Based on the user's input, generate a detailed drug instruction manual in JSON format.
      JSON Schema:
      {
        "name": "Drug Name",
        "indications": "Indications",
        "dosage": "Dosage",
        "contraindications": "Contraindications",
        "storage": "Storage",
        "sideEffects": "Side Effects",
        "usage_tips": "3-5 tips",
        "summary": "150-word summary"
      }
      If unrecognized, set name to "Unrecognized".
      Respond in **${lang === 'zh' ? 'SIMPLIFIED CHINESE' : 'ENGLISH'}** only. Return ONLY JSON.`;
    } else {
      return `You are a General Practitioner. 
      Perform a differential diagnosis based on symptoms/images.
      JSON Schema:
      {
        "urgency": "Low/Medium/High",
        "urgency_reason": "Reason",
        "summary": "100-word summary",
        "potential_conditions": [
          { "name": "Condition", "probability": "High/Med/Low", "explanation": "Why?", "medications": ["Meds"], "treatments": ["Advice"] }
        ],
        "lifestyle_advice": "Advice"
      }
      Respond in **${lang === 'zh' ? 'SIMPLIFIED CHINESE' : 'ENGLISH'}** only. Return ONLY JSON.`;
    }
};

const extractJSON = (text: string) => {
    const jsonMatch = text.match(/\{[\s\S]*\}/);
    if (jsonMatch) return JSON.parse(jsonMatch[0]);
    return JSON.parse(text);
};

// --- API Methods ---

export const getDrugInfoFromText = async (query: string, lang: Language): Promise<DrugInfo> => {
    const prompt = getSystemPrompt(lang, 'DRUG');
    const messages = [
        { role: 'system', content: prompt },
        { role: 'user', content: lang === 'zh' ? `查询药品：${query}` : `Identify drug: ${query}` }
    ];

    const text = await callQwen(messages);
    return extractJSON(text) as DrugInfo;
};

export const getDrugInfoFromImage = async (base64Image: string, lang: Language): Promise<DrugInfo> => {
    const prompt = getSystemPrompt(lang, 'DRUG');
    const messages = [
        {
            role: 'user',
            content: [
                { image: base64Image }, // DashScope supports data URI now
                { text: prompt + (lang === 'zh' ? "\n识别图中的药品" : "\nIdentify the drug") }
            ]
        }
    ];

    const text = await callQwenVL(messages);
    return extractJSON(text) as DrugInfo;
};

export const analyzeSymptoms = async (symptoms: string, base64Image: string | undefined, lang: Language): Promise<DiagnosisInfo> => {
    const prompt = getSystemPrompt(lang, 'DIAGNOSIS');

    if (base64Image) {
        const messages = [
            {
                role: 'user',
                content: [
                    { image: base64Image },
                    { text: prompt + `\n${lang === 'zh' ? "我的症状：" : "My symptoms: "}${symptoms || "None"}` }
                ]
            }
        ];
        const text = await callQwenVL(messages);
        return extractJSON(text) as DiagnosisInfo;
    } else {
        const messages = [
            { role: 'system', content: prompt },
            { role: 'user', content: lang === 'zh' ? `我的症状：${symptoms}` : `My symptoms: ${symptoms}` }
        ];
        const text = await callQwen(messages);
        return extractJSON(text) as DiagnosisInfo;
    }
};

export const askFollowUpQuestion = async (context: string, question: string, lang: Language): Promise<string> => {
    const systemPrompt = lang === 'zh' 
      ? "你是一位友善、专业的医疗助手。请根据提供的上下文回答追问。回答要简洁（100字以内），安抚用户情绪。"
      : "You are a friendly, professional medical assistant. Answer based on context. Keep it concise (under 100 words) and reassuring.";

    const messages = [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: `Context:\n${context}\n\nQuestion: ${question}` }
    ];

    return await callQwen(messages);
};

import React, { useState, useRef, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Camera, Sparkles, Stethoscope, Pill, ArrowRight, Activity, ScanLine, ImagePlus, X, Globe, Mail } from 'lucide-react';
import { AppMode, DrugInfo, DiagnosisInfo, LoadingState, Language } from './types';
import { t } from './translations';
import { getDrugInfoFromImage, getDrugInfoFromText, analyzeSymptoms } from './services/qwenService';
import { ResultCard } from './components/ResultCard';
import { DiagnosisResultCard } from './components/DiagnosisResultCard';
import { LoadingOverlay } from './components/LoadingOverlay';
import { Toast, ToastType } from './components/Toast';

type Tab = 'DRUG' | 'DIAGNOSIS';

// Optimization: Moved outside App to prevent re-renders on state changes
const AmbientBackground = React.memo(() => (
  <div className="fixed inset-0 overflow-hidden pointer-events-none -z-10 bg-slate-50">
     {/* Mesh Gradient Overlay */}
     <div className="absolute inset-0 opacity-40 bg-[radial-gradient(#e5e7eb_1px,transparent_1px)] [background-size:24px_24px]"></div>

    <motion.div 
      animate={{ 
        x: [0, 100, -50, 0], 
        y: [0, -50, 50, 0],
        scale: [1, 1.2, 0.9, 1] 
      }}
      transition={{ duration: 20, repeat: Infinity, ease: "easeInOut" }}
      className="absolute -top-20 -left-20 w-[600px] h-[600px] bg-blue-200/40 rounded-full blur-[100px]"
    />
    <motion.div 
      animate={{ 
        x: [0, -70, 30, 0], 
        y: [0, 80, -30, 0],
        scale: [1, 1.1, 1] 
      }}
      transition={{ duration: 15, repeat: Infinity, ease: "easeInOut", delay: 2 }}
      className="absolute top-[30%] -right-40 w-[500px] h-[500px] bg-purple-200/40 rounded-full blur-[100px]"
    />
  </div>
));

function App() {
  const [lang, setLang] = useState<Language>('zh');
  const [activeTab, setActiveTab] = useState<Tab>('DRUG');
  const [mode, setMode] = useState<AppMode>(AppMode.HOME);

  // Data States
  const [drugInfo, setDrugInfo] = useState<DrugInfo | null>(null);
  const [diagnosisInfo, setDiagnosisInfo] = useState<DiagnosisInfo | null>(null);

  const [loading, setLoading] = useState<LoadingState>({ isLoading: false, message: '' });

  // Toast State
  const [toast, setToast] = useState<{ message: string; type: ToastType; isVisible: boolean }>({
    message: '',
    type: 'info',
    isVisible: false
  });

  // Inputs
  const [searchQuery, setSearchQuery] = useState('');
  const [symptomsQuery, setSymptomsQuery] = useState('');
  const [diagnosisImage, setDiagnosisImage] = useState<string | null>(null);

  // Refs
  const drugFileInputRef = useRef<HTMLInputElement>(null);
  const diagnosisFileInputRef = useRef<HTMLInputElement>(null);

  const T = t[lang];

  // --- Handlers ---

  const showToast = (message: string, type: ToastType = 'info') => {
    setToast({ message, type, isVisible: true });
  };

  const closeToast = () => {
    setToast(prev => ({ ...prev, isVisible: false }));
  };

  const toggleLanguage = () => {
    setLang(prev => prev === 'zh' ? 'en' : 'zh');
    showToast(lang === 'zh' ? 'Switched to English' : '已切换至中文', 'success');
  };

  const handleDrugSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setLoading({ isLoading: true, message: T.loading_drug });
    try {
      const info = await getDrugInfoFromText(searchQuery, lang);
      setDrugInfo(info);
      setMode(AppMode.RESULT);
    } catch (error: any) {
      showToast(error.message || "Search failed", 'error');
    } finally {
      setLoading({ isLoading: false, message: '' });
    }
  };

  const handleDrugFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setLoading({ isLoading: true, message: T.loading_vision });

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64String = reader.result as string;
        const info = await getDrugInfoFromImage(base64String, lang);
        setDrugInfo(info);
        setMode(AppMode.RESULT);
      } catch (error: any) {
        showToast(`${T.upload_fail}: ` + (error.message || "Error"), 'error');
      } finally {
        setLoading({ isLoading: false, message: '' });
        if (drugFileInputRef.current) drugFileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  const handleDiagnosisFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onloadend = async () => {
        setDiagnosisImage(reader.result as string);
        if (diagnosisFileInputRef.current) diagnosisFileInputRef.current.value = '';
        showToast(T.image_attached, 'success');
    };
    reader.readAsDataURL(file);
  };

  const handleSymptomAnalysis = async () => {
    if (!symptomsQuery.trim() && !diagnosisImage) {
        showToast(T.missing_input, 'error');
        return;
    }

    setLoading({ isLoading: true, message: T.loading_diagnosis });
    try {
      const info = await analyzeSymptoms(symptomsQuery, diagnosisImage || undefined, lang);
      setDiagnosisInfo(info);
      setMode(AppMode.DIAGNOSIS_RESULT);
    } catch (error: any) {
       showToast(`${T.diagnosis_fail}: ` + (error.message || "Error"), 'error');
    } finally {
      setLoading({ isLoading: false, message: '' });
    }
  };

  const clearDiagnosisImage = () => setDiagnosisImage(null);

  const handleBack = useCallback(() => {
    setMode(AppMode.HOME);
    // Performance Optimization: 
    // Delay clearing data to ensure the exit animation (AnimatePresence) has the data it needs to render.
    setTimeout(() => {
        setDrugInfo(null);
        setDiagnosisInfo(null);
    }, 500); 
  }, []);

  // --- Render ---

  return (
    <div className="min-h-screen text-slate-800 font-sans relative overflow-x-hidden flex flex-col">
      <AmbientBackground />
      <Toast 
        message={toast.message} 
        type={toast.type} 
        isVisible={toast.isVisible} 
        onClose={closeToast} 
      />

      <input type="file" ref={drugFileInputRef} accept="image/*" capture="environment" className="hidden" onChange={handleDrugFileUpload} />
      <input type="file" ref={diagnosisFileInputRef} accept="image/*" capture="environment" className="hidden" onChange={handleDiagnosisFileUpload} />

      {/* Top Navigation Bar */}
      <div className="fixed top-0 left-0 right-0 z-40 p-6 flex justify-end pointer-events-none">
        <button 
          onClick={toggleLanguage}
          className="pointer-events-auto bg-white/70 backdrop-blur-md border border-slate-200 shadow-sm rounded-full px-4 py-2 flex items-center gap-2 hover:bg-white transition-all text-slate-700 font-medium text-sm"
        >
          <Globe size={16} />
          <span>{lang === 'zh' ? '中文 / English' : 'English / 中文'}</span>
        </button>
      </div>

      <div className="relative z-10 flex-1 flex flex-col">

        {loading.isLoading && <LoadingOverlay message={loading.message} type={activeTab} lang={lang} />}

        {/* --- RESULT VIEWS --- */}
        <AnimatePresence mode="wait">
          {mode === AppMode.RESULT && drugInfo ? (
            <motion.div 
              key="drug-result"
              initial={{ opacity: 0, scale: 0.98, x: 20 }} 
              animate={{ opacity: 1, scale: 1, x: 0 }} 
              exit={{ opacity: 0, scale: 0.98, x: 20 }}
              transition={{ duration: 0.3, ease: "easeOut" }}
              className="w-full h-screen fixed inset-0 z-20 bg-slate-50"
            >
              <ResultCard info={drugInfo} onBack={handleBack} lang={lang} />
            </motion.div>
          ) : mode === AppMode.DIAGNOSIS_RESULT && diagnosisInfo ? (
             <motion.div 
              key="diagnosis-result"
              initial={{ opacity: 0, scale: 0.98, x: 20 }} 
              animate={{ opacity: 1, scale: 1, x: 0 }} 
              exit={{ opacity: 0, scale: 0.98, x: 20 }}
              transition={{ duration: 0.3, ease: "easeOut" }}
              className="w-full h-screen fixed inset-0 z-20 bg-slate-50"
            >
              <DiagnosisResultCard info={diagnosisInfo} onBack={handleBack} lang={lang} />
