      JSON Schema:
      {
        "urgency": "Low/Medium/High",
        "urgency_reason": "Reason",
        "summary": "100-word summary",
        "potential_conditions": [
          { "name": "Condition", "probability": "High/Med/Low", "explanation": "Why?", "medications": ["Meds"], "treatments": ["Advice"] }
        ],
